import TomSelect from"../../tom-select.js";const getDom=t=>{if(t.jquery)return t[0];if(t instanceof HTMLElement)return t;if(-1<t.indexOf("<")){let e=document.createElement("div");return e.innerHTML=t.trim(),e.firstChild}return document.querySelector(t)};TomSelect.define("clear_button",function(e){const t=this,i=Object.assign({className:"clear-button",title:"Clear All",html:e=>`<div class="${e.className}" title="${e.title}">&times;</div>`},e);t.on("initialize",()=>{var e=getDom(i.html(i));e.addEventListener("click",e=>{t.clear(),e.preventDefault(),e.stopPropagation()}),t.control.appendChild(e)})});